import{_ as i,o as t,c as l,ai as o}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Desktop App Interaction Design","description":"","frontmatter":{"summary":"Desktop interaction blueprint for OpenSoul macOS and Control UI surfaces","read_when":["Designing or refactoring the desktop app UX","Aligning menu bar, chat, settings, and dashboard interactions"],"title":"Desktop App Interaction Design"},"headers":[],"relativePath":"reference/desktop-app-interaction-design.md","filePath":"reference/desktop-app-interaction-design.md","lastUpdated":null}'),a={name:"reference/desktop-app-interaction-design.md"};function n(s,e,r,d,c,u){return t(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="desktop-app-interaction-design-v1-1" tabindex="-1"><a class="header-anchor" href="#desktop-app-interaction-design-v1-1">#</a> Desktop App Interaction Design (v1.1)</h1><h2 id="_1-product-frame" tabindex="-1"><a class="header-anchor" href="#_1-product-frame">#</a> 1) Product Frame</h2><ul><li>Target users: <ul><li>Solo builders and developers running OpenSoul as an always-on assistant.</li><li>Operators managing channels, sessions, skills, nodes, and automation from one control point.</li></ul></li><li>Core task loop: <ul><li>Observe status -&gt; Intervene quickly -&gt; Configure safely -&gt; Verify health.</li></ul></li><li>Primary platform constraints: <ul><li>Menu bar app is a core entry point (<code>apps/macos/Sources/OpenSoul/MenuBar.swift</code>).</li><li>Quick controls are exposed in menu content (<code>apps/macos/Sources/OpenSoul/MenuContentView.swift</code>).</li><li>Full chat lives in a floating window/panel (<code>apps/macos/Sources/OpenSoul/WebChatSwiftUI.swift</code>).</li><li>Settings are tab-based (<code>apps/macos/Sources/OpenSoul/SettingsRootView.swift</code>).</li><li>Browser Control UI provides deep operations (<code>ui/src/ui/navigation.ts</code>).</li></ul></li></ul><h2 id="_2-existing-feature-coverage-must-keep" tabindex="-1"><a class="header-anchor" href="#_2-existing-feature-coverage-must-keep">#</a> 2) Existing Feature Coverage (Must Keep)</h2><h3 id="desktop-app-surfaces" tabindex="-1"><a class="header-anchor" href="#desktop-app-surfaces">#</a> Desktop app surfaces</h3><ul><li>Onboarding flow: <ul><li>Welcome, gateway selection, auth, wizard, permissions, CLI, onboarding chat, ready state</li><li>Source: <code>apps/macos/Sources/OpenSoul/OnboardingView+Pages.swift</code>.</li></ul></li><li>Menu bar quick controls: <ul><li>Active/pause, heartbeat, browser control, camera, exec approvals, canvas, voice wake, mic selection</li><li>Open dashboard, open chat, open canvas, talk mode, settings/about/debug/quit</li><li>Source: <code>apps/macos/Sources/OpenSoul/MenuContentView.swift</code>.</li></ul></li><li>Settings tabs: <ul><li>General, Channels, Voice Wake, Config, Instances, Sessions, Cron, Skills, Permissions, Debug, About</li><li>Source: <code>apps/macos/Sources/OpenSoul/SettingsRootView.swift</code>.</li></ul></li></ul><h3 id="control-ui-surfaces" tabindex="-1"><a class="header-anchor" href="#control-ui-surfaces">#</a> Control UI surfaces</h3><ul><li>Chat, overview, channels, instances, sessions, usage, cron, agents, skills, nodes, config, debug, logs</li><li>Source: <code>ui/src/ui/navigation.ts</code>.</li></ul><h2 id="_3-design-direction" tabindex="-1"><a class="header-anchor" href="#_3-design-direction">#</a> 3) Design Direction</h2><p>Use a hybrid of:</p><ul><li>GitHub-like structured workbench for status-heavy operations.</li><li>Notion-like calm canvas for writing, onboarding, and long-form assistant interaction.</li><li>Cursor-like high-speed command interaction for power users.</li></ul><p>Direction rules:</p><ul><li>Dark-first visual language with light-theme parity as secondary.</li><li>Keep information density high but scannable.</li><li>Preserve keyboard-first flows for daily operations.</li><li>Use semantic status colors and explicit state labeling.</li><li>Minimize mode confusion between menu bar quick actions and deep configuration.</li></ul><h2 id="_4-information-architecture" tabindex="-1"><a class="header-anchor" href="#_4-information-architecture">#</a> 4) Information Architecture</h2><h2 id="_4-1-surface-model" tabindex="-1"><a class="header-anchor" href="#_4-1-surface-model">#</a> 4.1 Surface model</h2><ul><li>Surface A: <code>Menu Quick Surface</code> (status + immediate controls).</li><li>Surface B: <code>Desktop Workbench</code> (power-user operational window).</li><li>Surface C: <code>Settings Center</code> (stable system configuration).</li><li>Surface D: <code>Control UI</code> (browser parity + remote operations).</li></ul><h2 id="_4-2-desktop-workbench-navigation" tabindex="-1"><a class="header-anchor" href="#_4-2-desktop-workbench-navigation">#</a> 4.2 Desktop Workbench navigation</h2><p>Use four top-level domains:</p><ol><li><code>Assist</code><ul><li>Chat</li><li>Canvas</li><li>Session switcher</li></ul></li><li><code>Operate</code><ul><li>Channels</li><li>Instances</li><li>Sessions</li><li>Cron</li><li>Usage</li></ul></li><li><code>Build</code><ul><li>Agents</li><li>Skills</li><li>Nodes</li></ul></li><li><code>System</code><ul><li>Overview/health</li><li>Config</li><li>Logs</li><li>Debug (gated by debug mode)</li></ul></li></ol><h2 id="_4-3-necessary-settings-grouping" tabindex="-1"><a class="header-anchor" href="#_4-3-necessary-settings-grouping">#</a> 4.3 Necessary settings grouping</h2><p>Group settings by user intent, while preserving all existing controls:</p><ol><li><code>Runtime</code><ul><li>OpenSoul active, launch at login, dock icon, icon animations.</li></ul></li><li><code>Connectivity</code><ul><li>Local/remote mode, SSH/direct transport, remote test, gateway status.</li></ul></li><li><code>Capabilities</code><ul><li>Canvas, camera, voice wake, talk mode, microphone routing.</li></ul></li><li><code>Operations</code><ul><li>Channels, sessions defaults, cron, instances behavior.</li></ul></li><li><code>Agent Platform</code><ul><li>Skills, agent capabilities, node permissions.</li></ul></li><li><code>Security</code><ul><li>Permissions, exec approval defaults, pairing states.</li></ul></li><li><code>Advanced</code><ul><li>Config raw/form editing, debug tools, logs.</li></ul></li><li><code>About</code><ul><li>Version/update/license.</li></ul></li></ol><h2 id="_4-4-feature-to-surface-mapping-implementation-baseline" tabindex="-1"><a class="header-anchor" href="#_4-4-feature-to-surface-mapping-implementation-baseline">#</a> 4.4 Feature-to-surface mapping (implementation baseline)</h2><table tabindex="0"><thead><tr><th>Existing capability</th><th>Primary surface</th><th>Secondary surface</th></tr></thead><tbody><tr><td>Quick status and toggles</td><td>Menu Quick Surface</td><td>Settings Center</td></tr><tr><td>Daily assistant chat</td><td>Menu chat panel</td><td>Desktop Workbench (Assist)</td></tr><tr><td>Channel operations</td><td>Desktop Workbench (Operate)</td><td>Control UI <code>/channels</code></td></tr><tr><td>Sessions and usage analysis</td><td>Desktop Workbench (Operate)</td><td>Control UI <code>/sessions</code>, <code>/usage</code></td></tr><tr><td>Cron management</td><td>Desktop Workbench (Operate)</td><td>Control UI <code>/cron</code></td></tr><tr><td>Skills and agents</td><td>Desktop Workbench (Build)</td><td>Control UI <code>/skills</code>, <code>/agents</code></td></tr><tr><td>Node and pairing operations</td><td>Desktop Workbench (Build/System)</td><td>Control UI <code>/nodes</code></td></tr><tr><td>Config editing and debug tools</td><td>Settings Center (Advanced)</td><td>Control UI <code>/config</code>, <code>/debug</code>, <code>/logs</code></td></tr></tbody></table><h2 id="_5-key-screen-specs" tabindex="-1"><a class="header-anchor" href="#_5-key-screen-specs">#</a> 5) Key Screen Specs</h2><h2 id="_5-1-screen-a-menu-quick-surface" tabindex="-1"><a class="header-anchor" href="#_5-1-screen-a-menu-quick-surface">#</a> 5.1 Screen A: Menu Quick Surface</h2><ul><li>Purpose: <ul><li>Give immediate confidence and control in under 5 seconds.</li></ul></li><li>Layout: <ul><li>Status block (gateway + heartbeat + pending approvals).</li><li>Quick toggles block.</li><li>Action launcher block.</li><li>System block (settings/about/quit).</li></ul></li><li>Interaction: <ul><li>Single-click menu icon opens chat panel.</li><li>Right-click opens quick menu.</li><li>All toggles reflect real backend state within one refresh cycle.</li></ul></li></ul><h2 id="_5-2-screen-b-desktop-workbench-home" tabindex="-1"><a class="header-anchor" href="#_5-2-screen-b-desktop-workbench-home">#</a> 5.2 Screen B: Desktop Workbench Home</h2><ul><li>Purpose: <ul><li>Serve as the power-user control center while keeping menu-first onboarding.</li></ul></li><li>Layout: <ul><li>Left rail: four domains.</li><li>Top bar: connection state, active session, global command input.</li><li>Main pane: selected domain.</li><li>Context pane: details, recent actions, warnings.</li></ul></li><li>Interaction: <ul><li><code>Cmd+K</code> command palette.</li><li><code>Cmd+1..4</code> switch domains.</li><li><code>Cmd+Shift+L</code> focus logs.</li></ul></li></ul><h2 id="_5-3-screen-c-assist-chat-canvas" tabindex="-1"><a class="header-anchor" href="#_5-3-screen-c-assist-chat-canvas">#</a> 5.3 Screen C: Assist (Chat + Canvas)</h2><ul><li>Purpose: <ul><li>Keep conversational work and visual outputs together.</li></ul></li><li>Layout: <ul><li>Chat timeline pane.</li><li>Tool events timeline strip.</li><li>Optional canvas preview pane with resizable divider.</li></ul></li><li>Interaction: <ul><li>Keep run controls sticky at the bottom.</li><li>Show tool output in side drawer, not modal.</li><li>Preserve context when switching sessions.</li></ul></li></ul><h2 id="_5-4-screen-d-operate-channels-sessions-cron-usage" tabindex="-1"><a class="header-anchor" href="#_5-4-screen-d-operate-channels-sessions-cron-usage">#</a> 5.4 Screen D: Operate (Channels/Sessions/Cron/Usage)</h2><ul><li>Purpose: <ul><li>Run and monitor operations safely.</li></ul></li><li>Layout: <ul><li>Table-first pages with filter/search row.</li><li>Persistent state chips (ok/degraded/disconnected/pending auth).</li></ul></li><li>Interaction: <ul><li>Fast filtering, batched actions, clear rollback for destructive actions.</li><li>Require explicit confirmation only for irreversible actions.</li></ul></li></ul><h2 id="_5-5-screen-e-settings-center" tabindex="-1"><a class="header-anchor" href="#_5-5-screen-e-settings-center">#</a> 5.5 Screen E: Settings Center</h2><ul><li>Purpose: <ul><li>Keep advanced controls available without overwhelming first-time users.</li></ul></li><li>Layout: <ul><li>Vertical section list by intent (Runtime, Connectivity, ...).</li><li>Main form pane with inline validation and explainers.</li><li>Optional diagnostics side panel for current gateway health.</li></ul></li><li>Interaction: <ul><li>Mark changed fields before save.</li><li>Keep &quot;Test remote&quot; near remote transport fields.</li><li>Keep sensitive actions visually separated (debug, reset, delete).</li></ul></li></ul><h2 id="_6-component-and-state-matrix" tabindex="-1"><a class="header-anchor" href="#_6-component-and-state-matrix">#</a> 6) Component and State Matrix</h2><table tabindex="0"><thead><tr><th>Component</th><th>Default</th><th>Hover</th><th>Focus</th><th>Active</th><th>Loading</th><th>Success</th><th>Error</th><th>Disabled</th><th>Permission</th></tr></thead><tbody><tr><td>Global status chip</td><td>Shows mode</td><td>Elevate</td><td>Focus ring</td><td>N/A</td><td>Pulsing dot</td><td>Green badge</td><td>Red badge + reason</td><td>Muted</td><td>Tooltip</td></tr><tr><td>Quick toggle row</td><td>Label + state</td><td>Highlight row</td><td>Focus outline</td><td>Switch on/off</td><td>Spinner for async save</td><td>Check toast</td><td>Inline error text</td><td>Reduced contrast</td><td>Shield icon</td></tr><tr><td>Action launcher button</td><td>Label + icon</td><td>Fill +1</td><td>Focus ring</td><td>Pressed depth</td><td>Spinner icon</td><td>Check icon</td><td>Warning icon</td><td>Muted</td><td>Lock icon</td></tr><tr><td>Table row (sessions/channels)</td><td>Compact row</td><td>Row highlight</td><td>Outline</td><td>Selected fill</td><td>Skeleton row</td><td>Status chip</td><td>Error badge</td><td>Muted text</td><td>Restricted badge</td></tr><tr><td>Destructive action</td><td>Secondary style</td><td>Warn tint</td><td>Warn focus</td><td>Confirm step</td><td>Busy lock</td><td>Undo toast</td><td>Sticky alert</td><td>Disabled</td><td>N/A</td></tr></tbody></table><h2 id="_7-token-and-visual-rules" tabindex="-1"><a class="header-anchor" href="#_7-token-and-visual-rules">#</a> 7) Token and Visual Rules</h2><ul><li>Typography: <ul><li>Use SF Pro for UI text, SF Mono for technical values (paths, ids, commands).</li><li>3-level hierarchy: title, section, compact body.</li></ul></li><li>Color: <ul><li>Dark-first neutral base for structure.</li><li>Suggested core palette: <ul><li><code>bg.app</code> <code>#0D1117</code></li><li><code>bg.panel</code> <code>#161B22</code></li><li><code>bg.elevated</code> <code>#1F2630</code></li><li><code>border.default</code> <code>#30363D</code></li><li><code>text.primary</code> <code>#E6EDF3</code></li><li><code>text.secondary</code> <code>#9DA7B3</code></li><li><code>accent.primary</code> <code>#2F81F7</code></li><li><code>accent.muted</code> <code>#1F6FEB</code></li><li><code>success</code> <code>#3FB950</code></li><li><code>warning</code> <code>#D29922</code></li><li><code>danger</code> <code>#F85149</code></li></ul></li><li>Keep contrast and spacing calm like Notion; keep status semantics explicit like GitHub.</li><li>Semantic tokens only for state (success/warn/error/info).</li><li>Do not encode status with color alone; always add text/icon.</li></ul></li><li>Spacing: <ul><li>4/8/12/16/24 scale.</li><li>Dense tables use 8-12 vertical rhythm.</li></ul></li><li>Motion: <ul><li>120-180ms for panel transitions.</li><li>80-120ms for button/toggle feedback.</li><li>No decorative motion on critical status updates.</li></ul></li></ul><h2 id="_8-accessibility-and-usability-baseline" tabindex="-1"><a class="header-anchor" href="#_8-accessibility-and-usability-baseline">#</a> 8) Accessibility and Usability Baseline</h2><ul><li>Full keyboard path for all primary operations.</li><li>Visible focus ring for every interactive element.</li><li>Hit target &gt;= 32 px for compact controls and &gt;= 40 px for primary actions.</li><li>Contrast target: <ul><li>4.5:1 for body text.</li><li>3:1 for large text and icons.</li></ul></li><li>Avoid hidden critical actions behind hover-only affordances.</li></ul><h2 id="_9-rollout-plan" tabindex="-1"><a class="header-anchor" href="#_9-rollout-plan">#</a> 9) Rollout Plan</h2><ol><li>Phase 1: Navigation and IA alignment <ul><li>Add unified domain model across desktop workbench and Control UI tabs.</li><li>Keep existing actions and APIs unchanged.</li></ul></li><li>Phase 2: Settings intent regrouping <ul><li>Reorder settings by user intent without removing current options.</li><li>Add inline explainers and state chips.</li></ul></li><li>Phase 3: Visual and interaction polish <ul><li>Apply tokenized spacing/type/color.</li><li>Add command palette and keyboard map overlay.</li></ul></li><li>Phase 4: Cross-surface consistency <ul><li>Align labels and states between menu, settings, and dashboard.</li></ul></li></ol><h2 id="_10-final-product-decisions" tabindex="-1"><a class="header-anchor" href="#_10-final-product-decisions">#</a> 10) Final Product Decisions</h2><ul><li>Keep menu-first as the default entry mode; <code>Desktop Workbench</code> is an advanced/power surface.</li><li>Keep <code>Debug</code> hidden by default for non-advanced users.</li><li>Keep <code>Control UI</code> browser-first; desktop app provides deep links and state parity, not full embed in v1.</li><li>Use dark-first visual strategy with GitHub + Notion interaction tone.</li></ul>',45)])])}const g=i(a,[["render",n]]);export{h as __pageData,g as default};
